#include <stdio.h>

long long binsearch(int (*predicate)(long long), long long left, long long right) {
    while (left + 1 != right) {
        long long mid = (left + right) / 2;
        if (predicate(mid)) {
            right = mid;
        } else {
            left = mid;
        }
    }
    return right;
}

int predicate1(long long idx, long long n) {
    return n <= 3 * idx * (idx + 1);
}

int predicate2(long long idx, long long acc, long long i) {
    return acc + i * (idx + 1);
}

int main() {
    long long n;
    scanf("%lld", &n);
    if (n == 0) {
        printf("0 0\n");
    } else {
        long long i = binsearch((int (*)(long long))predicate1, 0, 1e18);
        long long acc = 3 * (i - 1) * i;
        long long j = binsearch((int (*)(long long))predicate2, -1, 6);
        long long k = n - acc - i * j - 1;
        int dy[] = {0, 2, 2, 0, -2, -2};
        int dx[] = {2, 1, -1, -2, -1, 1};
        long long y = dy[(j + 1) % 6] + dy[j] * (i - 1) + dy[(j + 2) % 6] * k;
        long long x = dx[(j + 1) % 6] + dx[j] * (i - 1) + dx[(j + 2) % 6] * k;
        printf("%lld %lld\n", x, y);
    }
    return 0;
}
